SELECT   chromosome,   start_,   en,   pheno_4gp.string_val as country,   cm as half_ibd_cm,   pheno_4gp.genotype_id as genotype_id FROM     ibd_pheno pheno_aj,     (SELECT          genotype_id_1,          genotype_id_2,          chromosome,          start_,          en,          cm,          is_full_ibd      FROM          ibd_segment      WHERE          genotype_id_1 = 797501193268570 AND          NOT is_full_ibd AND          cm >= 7) AS segment,     ibd_pheno pheno_4gp WHERE     genotype_id_2 NOT IN (         SELECT             genotype_id_2         FROM             ibd_relation_stats         WHERE             genotype_id_1 = 797501193268570 AND             half >= 800     ) AND     pheno_4gp.genotype_id = segment.genotype_id_2 AND     pheno_aj.genotype_id = segment.genotype_id_2 AND     pheno_4gp.concept_id = 'phenotypic_concept.birth_country_4gp' AND     pheno_4gp.concept_name='country' AND     pheno_4gp.string_val <> 'US' AND     pheno_aj.concept_id = 'report.ancestry_composition' AND     pheno_aj.concept_name = 'proportion_ashkenazi' AND     pheno_aj.float_val <= 0.05 GROUP BY country, chromosome, start_, en, pheno_4gp.genotype_id, cm limit 1;
